SECRET_KEY = os.environ.get('MODEL_SECRET_KEY', secrets.token_hex(32))


class RestrictedUnpickler(joblib.numpy_pickle.NumpyUnpickler):
    """Restricted unpickler that only allows safe classes"""
    
    def find_class(self, module, name):
        # Only allow specific whitelisted modules
        allowed_modules = {
            'numpy', 'numpy.core', 'numpy.core.multiarray', 'numpy.core.numeric',
            'numpy.dtype', 'numpy.ndarray', 'scipy.sparse', 'scipy.sparse.csr',
            'builtins', 'collections', 'sklearn', 'xgboost', 'lightgbm'
        }
        
        # Check if module is in whitelist or starts with allowed prefixes
        module_allowed = False
        for allowed in ALLOWED_MODEL_TYPES:
            if module.startswith(allowed):
                module_allowed = True
                break
        
        if not module_allowed and module not in allowed_modules:
            raise ValueError(f"Attempted to load disallowed module: {module}.{name}")
        
        # Block dangerous builtins
        if module == 'builtins':
            dangerous_builtins = {'eval', 'exec', 'compile', '__import__', 'open'}
            if name in dangerous_builtins:
                raise ValueError(f"Attempted to load dangerous builtin: {name}")
        
        return super().find_class(module, name)


def restricted_joblib_load(filename):
    """Load joblib file with restricted unpickler"""
    with open(filename, 'rb') as f:
        unpickler = RestrictedUnpickler(f)
        return unpickler.load()


def generate_api_key():
    """Generate a secure API key"""
    return secrets.token_urlsafe(32)


def generate_model_signature(model_id: str, tenant_id: str) -> str:
    """Generate HMAC signature for model verification"""
    message = f"{model_id}:{tenant_id}".encode()
    return hmac.new(SECRET_KEY.encode(), message, hashlib.sha256).hexdigest()


def verify_model_signature(model_id: str, tenant_id: str, signature: str) -> bool:
    """Verify HMAC signature"""
    expected = generate_model_signature(model_id, tenant_id)
    return hmac.compare_digest(expected, signature)


def require_api_key(f):
    """Decorator to require API key authentication"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key or api_key not in API_KEYS:
            return jsonify({'error': 'Invalid or missing API key'}), 401
        request.tenant_id = API_KEYS[api_key]
        return f(*args, **kwargs)
    return decorated_function


@app.route('/api/register', methods=['POST'])
def register_tenant():
    """Register a new tenant and get API key"""
    data = request.get_json()
    tenant_id = data.get('tenant_id')
    
    if not tenant_id:
        return jsonify({'error': 'tenant_id required'}), 400
    
    api_key = generate_api_key()
    API_KEYS[api_key] = tenant_id
    
    return jsonify({
        'tenant_id': tenant_id,
        'api_key': api_key,
        'message': 'Tenant registered successfully'
    }), 201


@app.route('/api/models/upload', methods=['POST'])
@require_api_key
def upload_model():
    """Upload and validate a model file"""
    if 'model' not in request.files:
        return jsonify({'error': 'No model file provided'}), 400
    
    file = request.files['model']
    model_name = request.form.get('model_name', 'unnamed_model')
    model_version = request.form.get('version', '1.0')
    
    if file.filename == '':
        return jsonify({'error': 'Empty filename'}), 400
    
    # Generate unique model ID
    model_id = hashlib.sha256(
        f"{request.tenant_id}:{model_name}:{model_version}:{datetime.utcnow().isoformat()}".encode()
    ).hexdigest()[:16]
    
    # Save file temporarily
    temp_path = os.path.join(app.config['UPLOAD_FOLDER'], f"{model_id}.joblib")
    file.save(temp_path)
    
    try:
        # Load model with restricted unpickler
        model = restricted_joblib_load(temp_path)
        
        # Validate model has predict method
        if not hasattr(model, 'predict'):
            raise ValueError("Model must have a 'predict' method")
        
        # Generate signature
        signature = generate_model_signature(model_id, request.tenant_id)
        
        # Store model metadata
        MODELS[model_id] = {
            'model': model,
            'tenant_id': request.tenant_id,
            'name': model_name,
            'version': model_version,
            'signature': signature,
            'uploaded_at': datetime.utcnow().isoformat(),
            'path': temp_path
        }
        
        return jsonify({
            'model_id': model_id,
            'signature': signature,
            'message': 'Model uploaded successfully'
        }), 201
        
    except Exception as e:
        # Clean up temp file on error
        if os.path.exists(temp_path):
            os.remove(temp_path)
        return jsonify({'error': f'Failed to load model: {str(e)}'}), 400


@app.route('/api/models/<model_id>/predict', methods=['POST'])
@require_api_key
def predict(model_id):
    """Make predictions using uploaded model"""
    if model_id not in MODELS:
        return jsonify({'error': 'Model not found'}), 404
    
    model_data = MODELS[model_id]
    
    # Verify tenant ownership
    if model_data['tenant_id'] != request.tenant_id:
        return jsonify({'error': 'Unauthorized access to model'}), 403
    
    # Verify signature if provided
    signature = request.headers.get('X-Model-Signature')
    if signature and not verify_model_signature(model_id, request.tenant_id, signature):
        return jsonify({'error': 'Invalid model signature'}), 403
    
    try:
        data = request.get_json()
        input_data = data.get('input')
        
        if input_data is None:
            return jsonify({'error': 'No input data provided'}), 400
        
        # Convert input to numpy array
        X = np.array(input_data)
        
        # Make prediction
        model = model_data['model']
        predictions = model.predict(X)
        
        # Get prediction probabilities if available
        result = {'predictions': predictions.tolist()}
        if hasattr(model, 'predict_proba'):
            probabilities = model.predict_proba(X)
            result['probabilities'] = probabilities.tolist()
        
        return jsonify(result), 200
        
    except Exception as e:
        return jsonify({'error': f'Prediction failed: {str(e)}'}), 400


